var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"안녕하세요, 오라버니! 절 찾으셨나요?","JPN":" こんにちは、お兄さん！　私を呼びましたか？","ENG":"Hello, my brother! You were looking for me?","TWN":"你好，哥哥！你找我嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"네? 왜 그렇게 부르냐니… 설마 여자애가 개인적인 자리에서 오라버니라고 부르는 게 싫으신 건 아니죠?","JPN":" はい？　なぜお兄さんかって……まさかプライベートで女の子にお兄さんと呼ばれるのが嫌いなわけありませんよね？","ENG":"Huh? Why am I calling you that...? Are you uncomfortable being called that in a private room by a girl like me?","TWN":"呃？為什麼我要這麼叫你……你該不會討厭女生在私底下你哥哥吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"헤헤, 실은 첫만남 때부터 냄새가 제 친오라버니와 엄청 닮았다고 생각했거든요.","JPN":" へへっ、実は初対面の時から匂いが私のお兄さんとすごく似ていると思いました。","ENG":"Hehe. To be honest, I thought you smelled just like my older brother from the moment we first met.","TWN":"嘿嘿，其實打從我們第一次見面，我就覺得你身上的香味和我哥哥很像。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"오라버니는 절 엄청 아끼고 예뻐했어요. 그래서 정말 좋아했는데…","JPN":" お兄さんは私の事を可愛がってくれました。だから本当に好きだったんですが……","ENG":"He cared for me and loved me so much. So, I liked him too…","TWN":"我哥哥很關心我，也很愛我。所以，我真的很喜歡他…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"합성실험에서 탈락한 실패작들은 전부 죽고, 유일하게 저만 살아남은 거 있죠?","JPN":" 合成実験の失敗作たちはみんな死んで、私だけが生き残ってしまいましたから。","ENG":"But after all the other subjects failed the synthesis experiment and died, I was the only one left.","TWN":"但是從合成實驗中淘汰的失敗品沒有一個能活下來，唯一活下來就只有我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"와아- 이런 얘길 하면 다들 불쌍하다는 눈빛으로 쳐다보던데, 표정 하나 안 변하시네요.","JPN":" わあー、この話をするとみんなに可哀そうって目をされましたけど、全然表情が変わらないんですね。","ENG":"Wow...! People normally look at me with pity in their eyes when they hear this story. But you didn't even flinch.","TWN":"哇喔，每次說我這段故事，大家都會對我投以同情的眼光光，可是你完全無動於衷呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런 점도 정말 예전 오라버니랑 쏙 빼닮으셨어요!","JPN":" そういうところも私のお兄さんにそっくりです！","ENG":"Even that's so similar to my older brother!","TWN":"光是這一點，你就真的很像哥哥！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"사실, 친오라버니는 제 손으로 죽였어요.","JPN":" 実は、実のお兄さんを殺したのは私です。","ENG":"You see, I killed my brother.","TWN":"其實，是我親手殺死哥哥的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"많은 연구원들이 보는 앞에서, 마지막에 살아남은 한 실험체만 폐기를 면할 수 있었거든요.","JPN":" 多くの研究員が監視する中で、最後に残った実験体だけが処分を免れることができましたので。","ENG":"In front of all the researchers. Because only the last one standing could avoid being discarded.","TWN":"在研究人員面前，只有最後倖存的實驗體才能夠避免被銷毀的命運。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그래서 이 손에 오라버니의 피를 묻혔을 때 생각했어요.","JPN":" だからお兄さんを私の手にかけた時、思いました。","ENG":"So when my hands were covered in his blood,","TWN":"所以，當我手上沾滿哥哥的鮮血時，我心裡是這樣想的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"내가 죽게 된다면… 기왕이면 오리버니와 가장 닮은 사람에게 죽어버리자- 라고 말이에요.","JPN":" 私が死ぬことになったら……いっそのことお兄さんに一番似ている人に殺されようって、ですね。","ENG":"I thought, if I die... I'd like to die in the hands of someone who most resembles my older brother.","TWN":"若是有一天我必須要死……我希望死在最像哥哥的人手上。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"헤헤, 그러니까 제가 죽을 수 있는 임무를 맡기더라도 부담 갖지 마세요.","JPN":" へへっ、だから私が死ぬかもしれない任務を任せることになっても気楽に考えてください。","ENG":"Hehe, so don't feel so pressured to assign me to a mission that might kill me.","TWN":"嘿嘿，不過你別因為我把我的命交給你就感到有壓力。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"오히려 그게 제가 원하는 일이니까요.","JPN":" むしろそっちの方が本望です。","ENG":"It's actually something I want.","TWN":"因為這就是我所希望的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};